"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[5095],{33787:e=>{e.exports=JSON.parse('{"functions":[{"name":"Filter","desc":"Callback invoked for each raycast hit. Return `true` to allow the bullet\\nto pierce through the instance.\\n\\nMust be **synchronous** \u2014 yielding inside this callback terminates the cast\\nwith an error on the next frame.\\n\\nSignature: `(context: BulletContext, result: RaycastResult, velocity: Vector3) -> boolean`\\n\\nDefault: `nil` (no piercing)","params":[{"name":"callback","desc":"","lua_type":"(context: BulletContext, result: RaycastResult, velocity: Vector3) -> boolean"}],"returns":[{"desc":"","lua_type":"PierceBuilder"}],"function_type":"method","source":{"line":225,"path":"docs/SubBuilders.lua"}},{"name":"Max","desc":"Maximum total number of surfaces the bullet can pierce over its lifetime.\\n\\nDefault: `3`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"PierceBuilder"}],"function_type":"method","source":{"line":235,"path":"docs/SubBuilders.lua"}},{"name":"SpeedThreshold","desc":"Minimum speed in studs per second required for a pierce attempt.\\nBelow this speed the hit is treated as a solid terminal impact.\\n\\nDefault: `50`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"PierceBuilder"}],"function_type":"method","source":{"line":246,"path":"docs/SubBuilders.lua"}},{"name":"SpeedRetention","desc":"Fraction of speed retained after each pierce. Must be in `[0, 1]`.\\n`0.8` means 20% of speed is lost per pierce \u2014 deeper chains become\\nprogressively slower.\\n\\nDefault: `0.8`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"PierceBuilder"}],"function_type":"method","source":{"line":258,"path":"docs/SubBuilders.lua"}},{"name":"NormalBias","desc":"Restricts piercing to impacts above a minimum head-on angle. Must be\\nin `[0, 1]`. `1.0` = all angles allowed. `0.0` = only perfectly\\nperpendicular impacts pierce.\\n\\nDefault: `1.0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"PierceBuilder"}],"function_type":"method","source":{"line":270,"path":"docs/SubBuilders.lua"}},{"name":"PenetrationDepth","desc":"Maximum wall thickness in studs that the bullet can penetrate per pierce.\\nThe solver performs an internal second raycast to find the exit point \u2014 if\\nthe wall is thicker than this value the bullet stops inside it.\\n\\n`0` = no depth limit per pierce (the `ThicknessLimit` hard cap still applies).\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"PierceBuilder"}],"function_type":"method","source":{"line":284,"path":"docs/SubBuilders.lua"}},{"name":"PenetrationForce","desc":"Total penetration force budget. Each surface absorbs force proportional\\nto its thickness and the bullet\'s `BulletMass`. When the budget reaches\\nzero the bullet can no longer pierce.\\n\\n`0` = disabled (use `MaxPierceCount` alone for simple multi-pierce without\\nmomentum modeling).\\n\\nDefault: `0`","params":[{"name":"value","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"PierceBuilder"}],"function_type":"method","source":{"line":299,"path":"docs/SubBuilders.lua"}},{"name":"ThicknessLimit","desc":"Hard cap on wall thickness in studs. The solver\'s internal exit-point\\nraycast extends at most this many studs through a surface. Any wall\\nthicker than this is treated as impenetrable regardless of force budget\\nor `PenetrationDepth`.\\n\\nDefault: `500`","params":[{"name":"value","desc":"Must be > 0.","lua_type":"number"}],"returns":[{"desc":"","lua_type":"PierceBuilder"}],"function_type":"method","source":{"line":312,"path":"docs/SubBuilders.lua"}},{"name":"Done","desc":"Returns the root [BehaviorBuilder].","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"method","source":{"line":319,"path":"docs/SubBuilders.lua"}}],"properties":[],"types":[],"name":"PierceBuilder","desc":"Sub-builder for pierce configuration. Opened via [BehaviorBuilder:Pierce].\\nCall `:Done()` to return to the root [BehaviorBuilder].\\n\\n:::caution\\nPierce and bounce are mutually exclusive per hit. Pierce is evaluated first.\\nIf pierce succeeds, the bounce filter is not checked for that hit.\\n:::","source":{"line":209,"path":"docs/SubBuilders.lua"}}')}}]);